  1→<!DOCTYPE html>
  2→<html lang="en">
  3→<head>
  4→<meta charset="UTF-8"/>
  5→<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  6→<title>Custom RISC-V Instruction — Part 1</title>
  7→<style>
  8→  @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600&family=Syne:wght@400;600;700;800&display=swap');
  9→
